namespace sv_5faa14e5df454d59abab711c50799b9d.Services;

public class WarehouseInfo
{
    public required string Id { get; init; }
    public required string Name { get; init; }
}

/// <summary>
/// Scoped (per-circuit) service that holds the currently selected warehouse
/// and notifies all subscribed components when the selection changes.
/// </summary>
public class WarehouseStateService
{
    private static readonly List<WarehouseInfo> _warehouses =
    [
        new() { Id = "WH-A", Name = "Warehouse A" },
        new() { Id = "WH-B", Name = "Warehouse B" },
        new() { Id = "WH-C", Name = "Warehouse C" },
        new() { Id = "WH-D", Name = "Warehouse D" },
    ];

    public IReadOnlyList<WarehouseInfo> Warehouses => _warehouses;

    public string CurrentWarehouseId { get; private set; } = _warehouses[0].Id;

    public string CurrentWarehouseName =>
        _warehouses.First(w => w.Id == CurrentWarehouseId).Name;

    public event Action? OnChange;

    public void SetWarehouse(string warehouseId)
    {
        if (warehouseId == CurrentWarehouseId)
            return;

        CurrentWarehouseId = warehouseId;
        OnChange?.Invoke();
    }
}

namespace sv_5faa14e5df454d59abab711c50799b9d.Services;

/// <summary>
/// Scoped (per-circuit) service that tracks low-stock alert counts.
/// Exposes a simulated async query and an event so every subscribed
/// component re-renders when fresh data arrives.
/// </summary>
public class InventoryAlertService
{
    private readonly Random _random = new();

    public int CurrentAlertCount { get; private set; }

    public event Action? OnAlertCountChanged;

    /// <summary>
    /// Simulates a database query returning the number of items below
    /// minimum stock levels for the given warehouse.
    /// </summary>
    public async Task<int> GetLowStockCountAsync(string warehouseId)
    {
        // Simulate I/O latency
        await Task.Delay(150);
        return _random.Next(0, 16);
    }

    /// <summary>
    /// Called by the polling component after fetching fresh data.
    /// Updates shared state and notifies all subscribers.
    /// </summary>
    public void UpdateAlertCount(int count)
    {
        CurrentAlertCount = count;
        OnAlertCountChanged?.Invoke();
    }
}

