@page "/dashboard"
@rendermode InteractiveServer
@inject sv_5faa14e5df454d59abab711c50799b9d.Services.WarehouseStateService WarehouseState
@inject sv_5faa14e5df454d59abab711c50799b9d.Services.InventoryAlertService AlertService
@implements IDisposable

<PageTitle>Dashboard – @WarehouseState.CurrentWarehouseName</PageTitle>

<h1>Warehouse Dashboard</h1>

<div class="row mb-4">
    <div class="col-md-4">
        <div class="card text-bg-primary">
            <div class="card-body">
                <h5 class="card-title">Current Site</h5>
                <p class="card-text fs-4">@WarehouseState.CurrentWarehouseName</p>
            </div>
        </div>
    </div>
    <div class="col-md-4">
        <div class="card @(AlertService.CurrentAlertCount > 0 ? "text-bg-danger" : "text-bg-success")">
            <div class="card-body">
                <h5 class="card-title">Low-Stock Alerts</h5>
                <p class="card-text fs-4">@AlertService.CurrentAlertCount items</p>
            </div>
        </div>
    </div>
    <div class="col-md-4">
        <div class="card text-bg-secondary">
            <div class="card-body">
                <h5 class="card-title">Polling Status</h5>
                <p class="card-text fs-4">@(_polling ? "Active" : "Stopped") &bull; every 10 s</p>
            </div>
        </div>
    </div>
</div>

<p class="text-muted small">Last checked: @_lastChecked?.ToString("HH:mm:ss") ?? "—"</p>

@code {
    private CancellationTokenSource? _cts;
    private bool _polling;
    private DateTime? _lastChecked;

    protected override void OnInitialized()
    {
        WarehouseState.OnChange += HandleWarehouseChanged;
        AlertService.OnAlertCountChanged += HandleAlertChanged;
    }

    protected override async Task OnAfterRenderAsync(bool firstRender)
    {
        if (firstRender)
        {
            await FetchAlerts();
            StartPolling();
        }
    }

    private void StartPolling()
    {
        _cts?.Cancel();
        _cts = new CancellationTokenSource();
        _polling = true;
        _ = PollLoop(_cts.Token);
    }

    private async Task PollLoop(CancellationToken ct)
    {
        using var timer = new PeriodicTimer(TimeSpan.FromSeconds(10));
        try
        {
            while (await timer.WaitForNextTickAsync(ct))
            {
                await FetchAlerts();
            }
        }
        catch (OperationCanceledException)
        {
            // Expected on dispose or warehouse switch
        }
    }

    private async Task FetchAlerts()
    {
        var count = await AlertService.GetLowStockCountAsync(WarehouseState.CurrentWarehouseId);
        _lastChecked = DateTime.Now;
        // This updates the shared state and fires OnAlertCountChanged,
        // which notifies ALL subscribers (sidebar badge, this page, etc.)
        AlertService.UpdateAlertCount(count);
    }

    private async void HandleWarehouseChanged()
    {
        // Restart polling immediately for the new warehouse
        StartPolling();
        await FetchAlerts();
        await InvokeAsync(StateHasChanged);
    }

    private void HandleAlertChanged() => InvokeAsync(StateHasChanged);

    public void Dispose()
    {
        _polling = false;
        _cts?.Cancel();
        _cts?.Dispose();
        WarehouseState.OnChange -= HandleWarehouseChanged;
        AlertService.OnAlertCountChanged -= HandleAlertChanged;
    }
}

