+    private async Task PollLoop(CancellationToken ct)
+    {
+        using var timer = new PeriodicTimer(TimeSpan.FromSeconds(10));
+        try
+        {
+            while (await timer.WaitForNextTickAsync(ct))
+            {
+                await FetchAlerts();
+            }
+        }
+        catch (OperationCanceledException)
+        {
+            // Expected on dispose or warehouse switch
+        }
+    }
+
+    private async Task FetchAlerts()
+    {
+        var count = await AlertService.GetLowStockCountAsync(WarehouseState.CurrentWarehouseId);
+        _lastChecked = DateTime.Now;
+        // This updates the shared state and fires OnAlertCountChanged,
+        // which notifies ALL subscribers (sidebar badge, this page, etc.)
+        AlertService.UpdateAlertCount(count);
+    }
+
+    private async void HandleWarehouseChanged()
+    {
+        // Restart polling immediately for the new warehouse
+        StartPolling();
+        await FetchAlerts();
+        await InvokeAsync(StateHasChanged);
+    }
+
+    private void HandleAlertChanged() => InvokeAsync(StateHasChanged);
+
+    public void Dispose()
+    {
+        _polling = false;
+        _cts?.Cancel();
+        _cts?.Dispose();
+        WarehouseState.OnChange -= HandleWarehouseChanged;
+        AlertService.OnAlertCountChanged -= HandleAlertChanged;
+    }
+}
+

